runService.Heartbeat:Connect(function(deltaTime)
   currentAngle = currentAngle + rad(speed*deltaTime);
   local crosshairCenter = screenCenter;
   local color = white;
   --we dont need to reset this to 0 degree when it exceeds 360 cuz sin and cos works on all numbers (real) to infinity
   local currentGun = gameLogic.currentgun;

   if currentGun then
       if not currentGun.knife and currentGun.barrel and currentGun.data and currentGun.data.bulletspeed then
           local partCrame = currentGun.barrel;
           if partCrame then
               partCrame = partCrame.CFrame;
               local camP = pfCamera.basecframe.p;
               local _, gunPos, gunNorm = raycast(workspace, newRay(camP, partCrame.p - camP), {findFirstChild(workspace.Players, localPlayer.Team.Name), workspace.Terrain, workspace.Ignore, camera});
               local origin = gunPos + gunNorm*0.01;
               local ray = newRay(origin, partCrame.LookVector*currentGun.data.bulletspeed);
               local wall, pos = raycast(workspace, ray, {workspace.Players, workspace.Ignore, workspace.Terrain, camera}, false, true);
               if wall then
                   crosshairCenter = camera:WorldToViewportPoint(pos);
                   crosshairCenter = vector2(floor(crosshairCenter.x), floor(crosshairCenter.y));
                   local extent = wall.Size.magnitude*ray.Direction.Unit;
                   local wall1, exit = raycastwl(workspace, newRay(pos + extent, -extent), {wall}, true);
                   if wall1 then
                       local depth = (exit - pos).Magnitude;
                       color = depth > currentGun.data.penetrationdepth and unwallbangableColor or wallbangableColor;
                   end
               end
           end
       end



       line0.From = crosshairCenter + (vector2(cos(currentAngle), sin(currentAngle))*crosshairOffset);
       line0.To = line0.From + (vector2(cos(currentAngle), sin(currentAngle))*crosshairSize);
       line1.From = crosshairCenter + (vector2(cos(currentAngle + pi/2), sin(currentAngle + pi/2))*crosshairOffset);
