       --u can round their position for less blurryness
       --u can also use square instead of lines but iM LAZYYYy
       outlineLine0.From = line0.From;
       outlineLine1.From = line1.From;
       outlineLine2.From = line2.From;
       outlineLine3.From = line3.From;

       outlineLine0.To = line0.To;
       outlineLine1.To = line1.To;
       outlineLine2.To = line2.To;
       outlineLine3.To = line3.To;

       line0.Color = color;
       line1.Color = color;
       line2.Color = color;
       line3.Color = color;

       line0.Visible = true;
       line1.Visible = true;
       line2.Visible = true;
